// The GitHub 'get file' node (v1.1) returns the decoded file content
// directly in item.json.body as a plain string — no base64 needed.
const item = $input.first();

// Prefer .body (v1.1 decoded), fall back to manual base64 decode of .content
let raw;
if (item.json.body && typeof item.json.body === 'string') {
  raw = item.json.body;
} else if (item.json.content && typeof item.json.content === 'string') {
  // atob works in n8n's sandbox; strip newlines first
  raw = atob(item.json.content.replace(/\n/g, ''));
} else {
  throw new Error('GitHub file node returned neither .body nor .content. Keys: ' + Object.keys(item.json).join(', '));
}

const teamSkills = JSON.parse(raw);
return [{ json: { teamSkills } }];

// Prepare merged context for the Sprint Planner agent
const allItems = $input.all();

// Gather data from all merge inputs
let estimates = null;
let priorities = null;
let teamSkills = null;

for (const item of allItems) {
  if (item.json.estimates) estimates = item.json.estimates;
  if (item.json.output || item.json.text) {
    const raw = item.json.output || item.json.text || '';
    try {
      const cleaned = raw.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
      const parsed = JSON.parse(cleaned);
      if (parsed.high || parsed.medium || parsed.low) priorities = parsed;
    } catch (e) {}
  }
  if (item.json.teamSkills) teamSkills = item.json.teamSkills;
}

return [{
  json: {
    estimates: estimates || [],
    priorities: priorities || { high: [], medium: [], low: [] },
    teamSkills: teamSkills || { team: [] }
  }
}];

// Format and output the final sprint plan
const item = $input.first();
const planMarkdown = item.json.output || item.json.text || item.json.message || 'No plan generated.';

const timestamp = new Date().toISOString().split('T')[0];
const finalPlan = `# Sprint Plan - Generated ${timestamp}\n\n${planMarkdown}`;

console.log('=== SPRINT PLAN ===');
console.log(finalPlan);

return [{ json: { sprintPlan: finalPlan, generatedAt: timestamp } }];
